// Define all pages to audit
const pages = [
  { url: 'https://www.iaml.com/', name: 'Homepage' },
  { url: 'https://www.iaml.com/programs/employment-law-update', name: 'Employment Law Update' },
  { url: 'https://www.iaml.com/programs/advanced-employment-law', name: 'Advanced Employment Law' },
  { url: 'https://www.iaml.com/programs/the-california-hr-master-class', name: 'California HR Master Class' },
  { url: 'https://www.iaml.com/programs/employee-relations-law', name: 'Employee Relations Law' },
  { url: 'https://www.iaml.com/programs/labor-relations-101', name: 'Labor Relations 101' },
  { url: 'https://www.iaml.com/programs/employment-law-for-supervisors', name: 'Employment Law for Supervisors' },
  { url: 'https://www.iaml.com/about', name: 'About' },
  { url: 'https://www.iaml.com/faculty', name: 'Faculty' },
  { url: 'https://www.iaml.com/corporate-training', name: 'Corporate Training' }
];

return pages.map(p => ({ json: p }));

// Parse PageSpeed results for a single page
const items = $input.all();
const mobile = items[0]?.json || {};
const desktop = items[1]?.json || {};

// Helper to extract score
function getScore(data, category) {
  return Math.round((data.lighthouseResult?.categories?.[category]?.score || 0) * 100);
}

// Helper to extract metric value in ms
function getMetricMs(data, auditId) {
  const value = data.lighthouseResult?.audits?.[auditId]?.numericValue;
  return value ? Math.round(value) : null;
}

// Helper to extract CLS (already a decimal)
function getCLS(data) {
  const value = data.lighthouseResult?.audits?.['cumulative-layout-shift']?.numericValue;
  return value ? parseFloat(value.toFixed(3)) : null;
}

// Get the page URL from the request
const pageUrl = mobile.lighthouseResult?.requestedUrl || mobile.id || 'unknown';
const pageName = $('Batch Pages').first().json.name || pageUrl.split('/').pop() || 'Page';

const result = {
  page_url: pageUrl,
  page_name: pageName,

  // Scores
  pagespeed_mobile: getScore(mobile, 'performance'),
  pagespeed_desktop: getScore(desktop, 'performance'),
  accessibility_score: getScore(mobile, 'accessibility'),
  best_practices_score: getScore(mobile, 'best-practices'),
  seo_score: getScore(mobile, 'seo'),

  // Core Web Vitals (from mobile)
  lcp_ms: getMetricMs(mobile, 'largest-contentful-paint'),
  cls: getCLS(mobile),
  fid_ms: getMetricMs(mobile, 'max-potential-fid'),
  fcp_ms: getMetricMs(mobile, 'first-contentful-paint'),
  ttfb_ms: getMetricMs(mobile, 'server-response-time'),
  speed_index: getMetricMs(mobile, 'speed-index'),
  total_blocking_time_ms: getMetricMs(mobile, 'total-blocking-time'),

  // Resource sizes
  total_bytes: mobile.lighthouseResult?.audits?.['total-byte-weight']?.numericValue || 0,

  // Opportunities (for issue generation)
  opportunities: (mobile.lighthouseResult?.audits || {}),

  // Raw data for storage
  lighthouse_data: {
    mobile: mobile.lighthouseResult,
    desktop: desktop.lighthouseResult
  }
};

// Store result in workflow static data for accumulation across loop iterations
const staticData = $getWorkflowStaticData('global');
if (!staticData.pageResults) {
  staticData.pageResults = [];
}
staticData.pageResults.push(result);

return [{ json: result }];

// Get accumulated results from workflow static data
const staticData = $getWorkflowStaticData('global');
const allResults = staticData.pageResults || [];

// Clear static data for next run
staticData.pageResults = [];

if (allResults.length === 0) {
  return [{ json: { error: 'No page results to aggregate' } }];
}

// Calculate averages
const validMobile = allResults.filter(r => r.pagespeed_mobile > 0);
const validDesktop = allResults.filter(r => r.pagespeed_desktop > 0);
const validLcp = allResults.filter(r => r.lcp_ms > 0);
const validCls = allResults.filter(r => r.cls !== null);

const avg = (arr, key) => arr.length > 0 
  ? Math.round(arr.reduce((sum, r) => sum + (r[key] || 0), 0) / arr.length) 
  : null;

const avgDecimal = (arr, key) => arr.length > 0 
  ? parseFloat((arr.reduce((sum, r) => sum + (r[key] || 0), 0) / arr.length).toFixed(3)) 
  : null;

// Generate audit items from opportunities
const auditItems = [];
let itemCounter = 0;

// Common issue patterns to check
const issuePatterns = [
  { audit: 'render-blocking-resources', type: 'blocking_script', severity: 'high', title: 'Render-blocking resources' },
  { audit: 'unminified-javascript', type: 'unused_js', severity: 'medium', title: 'Unminified JavaScript' },
  { audit: 'unminified-css', type: 'unused_css', severity: 'medium', title: 'Unminified CSS' },
  { audit: 'unused-javascript', type: 'unused_js', severity: 'medium', title: 'Unused JavaScript' },
  { audit: 'unused-css-rules', type: 'unused_css', severity: 'medium', title: 'Unused CSS rules' },
  { audit: 'uses-responsive-images', type: 'large_image', severity: 'high', title: 'Properly sized images' },
  { audit: 'offscreen-images', type: 'no_lazy_load', severity: 'medium', title: 'Offscreen images not lazy-loaded' },
  { audit: 'uses-webp-images', type: 'unoptimized_image', severity: 'medium', title: 'Images not in next-gen format' },
  { audit: 'uses-text-compression', type: 'no_compression', severity: 'high', title: 'Text compression not enabled' },
  { audit: 'uses-rel-preconnect', type: 'no_preconnect', severity: 'low', title: 'Missing preconnect hints' },
  { audit: 'dom-size', type: 'large_dom', severity: 'medium', title: 'DOM too large' },
  { audit: 'mainthread-work-breakdown', type: 'main_thread_work', severity: 'high', title: 'Excessive main thread work' },
  { audit: 'bootup-time', type: 'long_task', severity: 'high', title: 'Long JavaScript execution time' }
];

// Process each page for issues
for (const pageResult of allResults) {
  const audits = pageResult.opportunities || {};

  for (const pattern of issuePatterns) {
    const audit = audits[pattern.audit];
    if (audit && audit.score !== undefined && audit.score < 0.9) {
      const savings = audit.numericValue || 0;
      const savingsBytes = audit.overallSavingsBytes || 0;

      // Only create item if there's meaningful savings
      if (savings > 100 || savingsBytes > 1000) {
        itemCounter++;
        auditItems.push({
          item_code: `SPEED-${String(itemCounter).padStart(3, '0')}`,
          issue_type: pattern.type,
          severity: audit.score < 0.5 ? 'critical' : (audit.score < 0.7 ? 'high' : pattern.severity),
          page_url: pageResult.page_url,
          title: `${pattern.title} on ${pageResult.page_name}`,
          description: audit.description || `${pattern.title} detected`,
          fix_suggestion: audit.details?.items?.[0]?.url ? `Optimize: ${audit.details.items[0].url}` : pattern.title,
          estimated_impact: savings > 1000 ? 'High' : (savings > 500 ? 'Medium' : 'Low'),
          estimated_savings_ms: Math.round(savings),
          estimated_savings_bytes: Math.round(savingsBytes)
        });
      }
    }
  }
}

// Count issues by severity
const criticalCount = auditItems.filter(i => i.severity === 'critical').length;
const highCount = auditItems.filter(i => i.severity === 'high').length;
const mediumCount = auditItems.filter(i => i.severity === 'medium').length;
const lowCount = auditItems.filter(i => i.severity === 'low').length;

const auditSummary = {
  audit_date: new Date().toISOString().split('T')[0],

  // Aggregate scores
  avg_pagespeed_mobile: avg(validMobile, 'pagespeed_mobile'),
  avg_pagespeed_desktop: avg(validDesktop, 'pagespeed_desktop'),
  avg_lcp_ms: avg(validLcp, 'lcp_ms'),
  avg_cls: avgDecimal(validCls, 'cls'),
  avg_fcp_ms: avg(allResults.filter(r => r.fcp_ms), 'fcp_ms'),
  avg_ttfb_ms: avg(allResults.filter(r => r.ttfb_ms), 'ttfb_ms'),
  avg_speed_index: avg(allResults.filter(r => r.speed_index), 'speed_index'),

  // Issue counts
  critical_issues: criticalCount,
  high_issues: highCount,
  medium_issues: mediumCount,
  low_issues: lowCount,

  // Data for storage
  page_results: allResults.map(r => ({
    page_url: r.page_url,
    page_name: r.page_name,
    pagespeed_mobile: r.pagespeed_mobile,
    pagespeed_desktop: r.pagespeed_desktop,
    lcp_ms: r.lcp_ms,
    cls: r.cls,
    fcp_ms: r.fcp_ms
  })),

  audit_items: auditItems,

  // For notifications
  total_pages: allResults.length,
  total_issues: auditItems.length
};

return [{ json: auditSummary }];

// Prepare audit items for bulk insert
const auditId = $('Insert Audit Record').first().json.id;
const items = $('Generate Audit Summary').first().json.audit_items || [];

if (!auditId) {
  throw new Error('Audit ID not found');
}

return items.map(item => ({
  json: {
    audit_id: auditId,
    ...item
  }
}));

// Generate notification content
const audit = $input.first().json;
const summary = $('Generate Audit Summary').first().json;

// Determine status emoji based on scores
const getMobileStatus = (score) => {
  if (score >= 90) return ':white_check_mark:';
  if (score >= 50) return ':large_yellow_circle:';
  return ':red_circle:';
};

const mobileDelta = audit.mobile_score_delta;
const desktopDelta = audit.desktop_score_delta;
const deltaStr = (d) => d > 0 ? `+${d}` : (d < 0 ? `${d}` : '0');

// Top 5 issues for Slack
const topIssues = summary.audit_items
  .sort((a, b) => {
    const sevOrder = { critical: 4, high: 3, medium: 2, low: 1 };
    return sevOrder[b.severity] - sevOrder[a.severity];
  })
  .slice(0, 5);

const issueList = topIssues.map((item, i) => {
  const sev = { critical: ':fire:', high: ':warning:', medium: ':large_yellow_circle:', low: ':information_source:' };
  return `${i + 1}. ${sev[item.severity]} *${item.item_code}*: ${item.title}`;
}).join('\n');

// Generate Slack blocks for interactive message
const slackBlocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: ':zap: Weekly Speed Audit Report', emoji: true }
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Week of ${audit.audit_date}* | ${summary.total_pages} pages audited`
    }
  },
  { type: 'divider' },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Mobile Score*\n${getMobileStatus(audit.avg_pagespeed_mobile)} ${audit.avg_pagespeed_mobile}/100 (${deltaStr(mobileDelta)})` },
      { type: 'mrkdwn', text: `*Desktop Score*\n${getMobileStatus(audit.avg_pagespeed_desktop)} ${audit.avg_pagespeed_desktop}/100 (${deltaStr(desktopDelta)})` },
      { type: 'mrkdwn', text: `*LCP*\n${audit.avg_lcp_ms}ms` },
      { type: 'mrkdwn', text: `*CLS*\n${audit.avg_cls}` }
    ]
  },
  { type: 'divider' },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Issues Found:* :fire: ${audit.critical_issues} critical | :warning: ${audit.high_issues} high | :large_yellow_circle: ${audit.medium_issues} medium | :information_source: ${audit.low_issues} low`
    }
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Top Issues to Address:*\n${issueList}`
    }
  },
  { type: 'divider' },
  {
    type: 'actions',
    elements: [
      {
        type: 'button',
        text: { type: 'plain_text', text: ':white_check_mark: Approve All', emoji: true },
        style: 'primary',
        action_id: 'approve_all',
        value: audit.id
      },
      {
        type: 'button',
        text: { type: 'plain_text', text: ':ballot_box_with_check: Approve Critical/High', emoji: true },
        action_id: 'approve_critical_high',
        value: audit.id
      },
      {
        type: 'button',
        text: { type: 'plain_text', text: ':fast_forward: Defer to Next Week', emoji: true },
        action_id: 'defer',
        value: audit.id
      }
    ]
  }
];

// Generate email HTML
const emailHtml = `
<h2>Weekly Speed Audit Report</h2>
<p><strong>Week of ${audit.audit_date}</strong> | ${summary.total_pages} pages audited</p>

<h3>Performance Scores</h3>
<table style="border-collapse: collapse; width: 100%;">
  <tr style="background: #f5f5f5;">
    <th style="padding: 8px; text-align: left;">Metric</th>
    <th style="padding: 8px; text-align: center;">Score</th>
    <th style="padding: 8px; text-align: center;">Change</th>
  </tr>
  <tr>
    <td style="padding: 8px;">Mobile PageSpeed</td>
    <td style="padding: 8px; text-align: center;"><strong>${audit.avg_pagespeed_mobile}</strong>/100</td>
    <td style="padding: 8px; text-align: center; color: ${mobileDelta >= 0 ? 'green' : 'red'};">${deltaStr(mobileDelta)}</td>
  </tr>
  <tr>
    <td style="padding: 8px;">Desktop PageSpeed</td>
    <td style="padding: 8px; text-align: center;"><strong>${audit.avg_pagespeed_desktop}</strong>/100</td>
    <td style="padding: 8px; text-align: center; color: ${desktopDelta >= 0 ? 'green' : 'red'};">${deltaStr(desktopDelta)}</td>
  </tr>
  <tr>
    <td style="padding: 8px;">LCP</td>
    <td style="padding: 8px; text-align: center;">${audit.avg_lcp_ms}ms</td>
    <td style="padding: 8px; text-align: center;">-</td>
  </tr>
  <tr>
    <td style="padding: 8px;">CLS</td>
    <td style="padding: 8px; text-align: center;">${audit.avg_cls}</td>
    <td style="padding: 8px; text-align: center;">-</td>
  </tr>
</table>

<h3>Issues Found</h3>
<ul>
  <li><strong>${audit.critical_issues}</strong> Critical</li>
  <li><strong>${audit.high_issues}</strong> High</li>
  <li><strong>${audit.medium_issues}</strong> Medium</li>
  <li><strong>${audit.low_issues}</strong> Low</li>
</ul>

<h3>Top Issues</h3>
<ol>
${topIssues.map(item => `  <li><strong>[${item.severity.toUpperCase()}]</strong> ${item.title}</li>`).join('\n')}
</ol>

<p><a href="https://iaml-dashboard.vercel.app/dashboard/digital/speed-audit" style="background: #0066cc; color: white; padding: 10px 20px; text-decoration: none; border-radius: 4px;">View Full Report & Approve</a></p>
`;

return [{
  json: {
    audit_id: audit.id,
    slack_blocks: slackBlocks,
    slack_text: `Weekly Speed Audit: Mobile ${audit.avg_pagespeed_mobile}/100 | ${summary.total_issues} issues found`,
    email_html: emailHtml,
    email_subject: `Weekly Speed Audit: ${audit.avg_pagespeed_mobile}/100 Mobile | ${summary.total_issues} issues`,
    audit: audit,
    summary: summary
  }
}];
